import json
from flask import Flask, request, jsonify
app = Flask(__name__)

@app.route('/jitume', methods=['POST'])
def jitume():
    '''
    Pokea maombi ya JSON kutoka kwa mteja, halafu:
    1. Thibitisha data iko sawa na halina mambo ya kijinga
    2. Rudisha jibu la kirafiki na ujumbe wa shukrani
    '''
    try:
        data = request.get_json(force=False, silent=True) or {}
        kazi = data.get('kazi', '').strip()
        if not kazi:
            return jsonify({'status': 'error', 'message': 'Tafadhali jaza kazi unayotaka kusaidia nao!'}), 400

        # Rudisha ujumbe wa shukrani kwa msaada
        return jsonify({
            'status': 'success',
            'message': f'Asante kwa kujitolea kusaidia katika {kazi}! Tunakushukuru kwa moyo wako mzuri.'
        })
    except Exception as e:
        return jsonify({'status': 'error', 'message': 'Kuna tatizo dogo, jaribu tena baadaye.'}), 500

