import json
from flask import Flask, request
app = Flask(__name__)

@app.route("/profile")
def profile():
    '''
    Pata taarifa za mtumiaji kutoka kwa request kwa format ya JSON.
    Hakikisha data inafuatana na muundo sahihi kwa kutumia `json.loads()`.
    Rudisha taarifa zilizokaguliwa kwa mfano:

    data = json.loads(request.data)
    return {"status": "success", "user_info": {"jina": data.get("jina"), "umri": data.get("umri")}}
    '''
    try:
        data = json.loads(request.data)
        # Validate na filter data muhimu tu
        user_info = {
            "jina": data.get("jina", "").strip(),
            "umri": int(data.get("umri", 0)) if data.get("umri") else 0
        }
        return {"status": "success", "user_info": user_info}
    except Exception as e:
        return {"status": "hitilafu", "message": "Data haifai"}

