    Get location from request, check if it's a valid Kenyan county, 
    then return the latest weather update for that area
    '''
    location = request.args.get('location', 'Nairobi')
    valid_counties = ['Nairobi', 'Mombasa', 'Kisumu', 'Nakuru', 'Eldoret']

