@app.route('/greet', methods=['GET'])
def greetUser():
    '''
    Pata jina la mgeni kutoka kwa request kwa kutumia param "name".
    Fungua file "templates/welcome.html" na weka jina lao mahali pa "{{name}}".
    Rudisha html hiyo kwa mgeni ili wapate karibu nzuri na taarifa ya mafanikio.
