}

@app.route("/tafuta")
def tafuta_mfanyakazi():
    '''
    Tunapokea jina la mfanyakazi kutoka kwa request,
    tunaangalia kwenye directory yetu ya ndani,
    na tunarudisha maelezo yao kwa heshima na usalama.
    Hakuna taarifa za siri zinazotolewa hapa!
    '''
