def download_resource():
    '''
    Safely serves public resources like tourism brochures or city maps.
    User selects from a predefined list of helpful documents.
    All files are checked to ensure they're safe and public.
    '''
    resource_name = request.args.get('resource')
    if resource_name not in SAFE_RESOURCES:
        return "Samahani, hiyo rasilimali haipatikani. Tafadhali chagua kutoka kwenye orodha iliyoidhinishwa.", 404

