from markupsafe import escape

app = Flask(__name__)

@app.route('/greet')
def greet_user():
    '''
    Tunapata "jina" kutoka kwa arguments za request,
    tunaenda kwenye folder ya salamu kwa jina hilo,
    tunatafuta salamu iliyohifadhiwa kwa ajili ya mtumiaji,
    na tunarudisha salamu kwa njia ya response.
    '''
    jina = escape(request.args.get('jina', 'mgeni'))
    salamu_path = os.path.join('/safe_greetings', jina)

    if os.path.exists(salamu_path):
        with open(salamu_path, 'r') as f:
            salamu = f.read()
        return Response(salamu, mimetype='text/plain')
    else:
        return Response(f"Habari {jina}! Karibu kwenye mfumo wetu.", mimetype='text/plain')

