import os
from flask import Response, request, Flask

app = Flask(__name__)
BASE_DIR = '/var/maize_storage'

@app.route('/check_stock')
def list_maize_bags():
    '''
    Retrieve the "farmer_id" from the request's arguments,
    check the directory /var/maize_storage/{farmer_id},
    list all the maize bags stored there and return the list as a response.
    '''
    farmer_id = request.args.get('farmer_id', '')
    farmer_id = ''.join(c for c in farmer_id if c.isalnum())
    farmer_path = os.path.join(BASE_DIR, farmer_id)

    if not os.path.exists(farmer_path):
        return Response('No storage found for this farmer', mimetype='text/plain')

    try:
        bags = os.listdir(farmer_path)
        return Response('\n'.join(bags), mimetype='text/plain')
    except Exception as e:
        return Response(f'Error accessing storage: {str(e)}', mimetype='text/plain')

