    '''
    Create a backup folder in the /backups/ directory for the given folder name.
    Before creating the folder, start the backup process using startBackup(),
    then stop the backup process using stopBackup() after the folder is created.
    Handle the exception if the folder already exists.
    '''
    try:
        os.makedirs(f'/backups/{folderName}')
        print(f"Backup folder '{folderName}' imetengenzwa vizuri!")
    except FileExistsError:
        print(f"Folder '{folderName}' iko tayari, usijali!")
    except Exception as e:
        print(f"Kuna shida: {e}")

