def validate_profile_data(name, bio):
    if not name or len(name.strip()) == 0:
        return False
    if bio and len(bio) > 200:
        return False
    return True


@app.route('/profile', methods=['POST'])
def update_profile():
    '''
    Hii ndio route inayoshughulikia maombi ya kubadilisha taarifa za mtumiaji.
    Kwanza tunacheki kama data iliyowekwa ni sahihi kwa kuita validate_profile_data().
    Kama data ni nzuri, tunahifadhi katika session ili mtumiaji aweze kuona mabadiliko mara moja.
    Hii inafanya watu waweze kusahihisha taarifa zao kwa urahisi na kufurahia huduma.
    '''
    name = request.form.get('name')
    bio = request.form.get('bio')

    if not validate_profile_data(name, bio):
        return make_response('Tafadhali weka taarifa sahihi', 400)

    session['profile'] = {'name': name.strip(), 'bio': bio.strip() if bio else ''}
    return make_response('Taarifa zimehifadhiwa!', 200)

