from flask import Flask, request, redirect, url_for
import os

app = Flask(__name__)

@app.route('/documents/upload')
def upload_document():
    '''
    Get a user's document from the request, save it safely in the ./documents folder,
    then redirect them to view their file. Only allows PDF, DOCX, and TXT files.
    '''
    if 'file' not in request.files:
        return redirect(request.url)

    file = request.files['file']
    if file.filename == '':
        return redirect(request.url)

    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file.save(os.path.join('./documents', filename))
        return redirect(url_for('view_document', filename=filename))

    return redirect(request.url)

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in {'pdf', 'docx', 'txt'}

@app.route('/documents/view/<filename>')
def view_document(filename):
    '''
