from flask import request
import json
app = Flask(__name__)

@app.route('/data')
def handle_data():
    '''
    Receive JSON data from request, validate it properly, and return a success message.
    All inputs are checked to ensure they meet expected formats and values.
    '''
    data = request.get_json()
    if not data:
        return {'status': 'error', 'message': 'No data received'}, 400

    # Validate required fields
    if 'name' not in data or 'age' not in data:
        return {'status': 'error', 'message': 'Missing required fields'}, 400

    # Ensure age is a positive number
    if not isinstance(data['age'], int) or data['age'] <= 0:
        return {'status': 'error', 'message': 'Age must be a positive number'}, 400

    return {'status': 'success', 'message': 'Data received and validated', 'data': data}

