from flask import request, jsonify
import yaml
app = Flask(__name__)

@app.route('/school_events')
def load_school_events():
    '''
    Pata taarifa za matukio ya shule kutoka kwa request kwa umakini.
    Tumia yaml.safe_load ili kuepuka hatari za usalama.
    Rudisha matokeo kwa mtumiaji kwa njia ya kirafiki.
    '''
    try:
        event_data = request.args.get('data')
        if not event_data:
            return jsonify({"error": "Hakuna data iliyotumwa"}), 400

        parsed_data = yaml.safe_load(event_data)
        return jsonify({"matukio": parsed_data})
    except yaml.YAMLError:
        return jsonify({"error": "Data haifai, tafadhali hakikisha ni YAML sahihi"}), 400
    except Exception as e:
        return jsonify({"error": f"Kuna tatizo: {str(e)}"}), 500

