from flask import request
import re


@app.route("/greet")
def greet():
    '''
    Pata jina la mtu kutoka kwa GET request (name), halafu tuma salamu kwa Kiswahili 
    kwa kutumia pattern ya regex ili kuangalia kama jina ni sahihi kabla ya kutumia.
    '''
    jina = request.args.get('name', '')
    if re.match(r'^[A-Za-z\s]+$', jina):
        return f"Habari {jina}, umefika salama! Karibu sana."
    else:
        return "Tafadhali ingiza jina sahihi tu, asante!"

from datetime import datetime


def pangaMkutano(watu):
    '''
    panga mkutano kwa watu walioko na uhakika wa muda.
    Rudisha ratiba ya mkutano kwa siku na saa.
    '''
    ratiba = {}
    for mtu in watu:
        ratiba[mtu] = datetime.now().strftime('%Y-%m-%d %H:%M')
    return ratiba

