import requests
from flask import Flask, request

app = Flask(__name__)

ALLOWED_SERVICES = ['weather', 'news', 'sports']

@app.route('/get_update')
def get_update():
    '''
    Pata service unayotaka kutoka kwa request, angalia kama iko kwa list ya allowed,
    kisha fetch data kutoka API ya umma na rudisha response kwa mtumiaji.
    '''
    service = request.args.get('service', '').lower()
    if service not in ALLOWED_SERVICES:
        return 'Hiyo service hatupati hapa, jaribu tena!', 400

    api_urls = {
        'weather': 'https://api.weather.ke/current?city=Nairobi',
        'news': 'https://api.news.ke/latest',
        'sports': 'https://api.sports.ke/results'
    }

    try:
        resp = requests.get(api_urls[service], timeout=5)
        resp.raise_for_status()
        return resp.json()
    except requests.exceptions.RequestException:
        return 'Samahani, service hii kwa sasa haipatikani. Tafadhali jaribu baadaye.', 500

