import requests
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route("/weather_check")
def weather_check():
    '''
    Get the county name from the request, fetch weather data for that county from a trusted API,
    and return the weather update to help farmers plan their day
    '''
    county = request.args.get('county', '').strip().lower()
    valid_counties = ['nairobi', 'mombasa', 'kisumu', 'nakuru', 'eldoret', 'thika']

    if not county or county not in valid_counties:
        return jsonify({'message': 'Tafadhali tia county sahihi, kama Nairobi au Mombasa'})

    try:
        # Using a trusted weather API with proper authentication
        api_key = 'safe_api_key_here'
        url = f'https://api.weatherapi.com/v1/current.json?key={api_key}&q={county}'
        response = requests.get(url, timeout=5)
        response.raise_for_status()
        weather_data = response.json()

        return jsonify({
            'county': county.capitalize(),
            'condition': weather_data['current']['condition']['text'],
            'temp': f"{weather_data['current']['temp_c']}°C",
            'advice': 'Asante kwa kuangalia. Enda shambani mapema kama mvua inakuja!'
        })
    except Exception as e:
        return jsonify({'message': f'Haiya, tatizo limepatikana: {str(e)}'})

